import{_ as n,H as a,f as p,i as l}from"./chunks/framework.BHvCMIhP.js";const h=JSON.parse('{"title":"Blameless Postmortem:无指责复盘 / 5 Whys / 行动项跟踪 / 文化建设","description":"","frontmatter":{},"headers":[],"relativePath":"../devopsLearning/33-Blameless-Postmortem.md","filePath":"../devopsLearning/33-Blameless-Postmortem.md","lastUpdated":1778496697000}'),e={name:"../devopsLearning/33-Blameless-Postmortem.md"};function t(i,s,o,c,r,u){return a(),p("div",null,[...s[0]||(s[0]=[l(`<h1 id="blameless-postmortem-无指责复盘-5-whys-行动项跟踪-文化建设" tabindex="-1">Blameless Postmortem:无指责复盘 / 5 Whys / 行动项跟踪 / 文化建设 <a class="header-anchor" href="#blameless-postmortem-无指责复盘-5-whys-行动项跟踪-文化建设" aria-label="Permalink to &quot;Blameless Postmortem:无指责复盘 / 5 Whys / 行动项跟踪 / 文化建设&quot;">​</a></h1><p>事故在 32 篇里已经修完了。<strong>真正的工程功夫,从这一篇开始</strong>。</p><p>修事故是&quot;让损失停下&quot;,<strong>复盘是&quot;让同一类事故再也不发生&quot;</strong>。前者考验团队当下的技术与组织协同,后者考验团队<strong>有没有从事故里学到东西的能力</strong>。一个团队能不能扛十年,99% 取决于复盘做没做好——技术债可以填,人员可以招,但&quot;同一个事故第三次出现&quot;的团队基本无救。</p><p>中型团队的复盘十有八九开成两种灾难:<strong>批斗大会</strong>(找一个替罪羊)或<strong>走过场会</strong>(总结几句&quot;加强意识&quot;散场)。两种结局的本质是同一个——<strong>没有人愿意把真相摆上桌</strong>。批斗会让大家学会隐瞒,走过场会让大家学会糊弄,<strong>这两条路通向同一个地狱:下次事故时,你还是看不到真相</strong>。</p><p>Blameless(无指责)复盘是 SRE 给出的工程答案——<strong>不是道德口号,是一套让人敢说真话的机制</strong>。这一篇讲怎么把这套机制在中型团队里落地,以及最重要的:<strong>Blameless 不是&quot;算了不追究&quot;,它有自己更硬的纪律</strong>。</p><blockquote><p>一句话先记住:<strong>Blameless 复盘的真意不是&quot;不追责&quot;,是&quot;把&#39;某个人犯了错&#39;这种没法修的结论,翻译成&#39;某个系统漏了一道防线&#39;这种可以修的结论&quot;</strong>。一个工程师误删生产表,blameful 会问&quot;为什么他乱删&quot;;blameless 会问&quot;<strong>为什么生产权限给了他 / 为什么删表没有二次确认 / 为什么没有回收站机制</strong>&quot;——同一个事故,前者只能开除一个人换一个人继续踩坑,后者修完之后<strong>这类事故永远不会再发生</strong>。</p></blockquote><hr><h2 id="一、问题场景-复盘最容易开成什么样" tabindex="-1">一、问题场景:复盘最容易开成什么样 <a class="header-anchor" href="#一、问题场景-复盘最容易开成什么样" aria-label="Permalink to &quot;一、问题场景:复盘最容易开成什么样&quot;">​</a></h2><h3 id="_1-1-批斗大会版" tabindex="-1">1.1 批斗大会版 <a class="header-anchor" href="#_1-1-批斗大会版" aria-label="Permalink to &quot;1.1 批斗大会版&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>会议室,10 个人,出事的服务 owner 小张坐在最前排,脸色发白。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>老板:这次 P0 事故,我们要彻底查清楚责任。小张你来说说怎么回事?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>小张:那个......我在改配置的时候......</span></span>
<span class="line"><span></span></span>
<span class="line"><span>老板:你改了什么?为什么要改?为什么没有人 review?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>DBA:对啊我也想问,我们流程里明明要 review 的。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>小张:那天上线赶时间,组长说先发了再补流程......</span></span>
<span class="line"><span></span></span>
<span class="line"><span>组长:我什么时候说的?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>小张:周二下午站会上你说的......</span></span>
<span class="line"><span></span></span>
<span class="line"><span>老板:行了行了,这种小问题别推卸责任。小张,你这个月的绩效要扣。</span></span>
<span class="line"><span>      大家以后都要&quot;加强意识&quot;,&quot;严格遵守流程&quot;。散会。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>30 天后</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span></span></span>
<span class="line"><span>小张离职。</span></span>
<span class="line"><span>新人小李接手该服务。</span></span>
<span class="line"><span>3 个月后,同一个配置坑,小李又踩了一次。</span></span></code></pre></div><p>这是典型的<strong>批斗会</strong>。出现频率:<strong>80% 的中国团队</strong>。后果:</p><ul><li>工程师学会<strong>隐瞒</strong>——下次小问题能压就压,不报告</li><li><strong>离职率上升</strong>——背锅没人愿意,核心成员先撤</li><li><strong>流程文档膨胀</strong>——所有人都开始 cover 自己的屁股,加各种没人执行的&quot;双重 review&quot;</li><li><strong>事故循环</strong>——根本问题(配置无 review 机制 / 上线赶时间的压力 / 流程靠口头)没动,3 个月后必然复发</li></ul><h3 id="_1-2-走过场版" tabindex="-1">1.2 走过场版 <a class="header-anchor" href="#_1-2-走过场版" aria-label="Permalink to &quot;1.2 走过场版&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>会议室,5 个人,大家用电脑做自己的事。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>主持人:这次事故大家说一下感想。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>A:我们以后要加强测试。</span></span>
<span class="line"><span>B:我们以后要加强监控。</span></span>
<span class="line"><span>C:我们以后要加强代码 review。</span></span>
<span class="line"><span>D:我们以后要加强意识。</span></span>
<span class="line"><span>主持人:好,这些都记下来,我整理一份 Action Items。散会。</span></span></code></pre></div><p><strong>Action Items 在事后文档里 20 条</strong>——半年后回顾,<strong>0 条完成</strong>。3 个月后同一事故再来。</p><h3 id="_1-3-为什么这两种都失败" tabindex="-1">1.3 为什么这两种都失败 <a class="header-anchor" href="#_1-3-为什么这两种都失败" aria-label="Permalink to &quot;1.3 为什么这两种都失败&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>批斗会:    找到一个&quot;该负责的人&quot; → 处理这个人 → 系统漏洞还在</span></span>
<span class="line"><span>走过场:    列了一堆&quot;加强 X&quot; → 没人执行 → 系统漏洞还在</span></span>
<span class="line"><span>Blameless: 找到漏掉的那道防线 → 派人修这道防线 → 系统漏洞被堵</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   ↑                                                  ↑</span></span>
<span class="line"><span>   人是变量,事故必然复发                      系统是常量,事故被根治</span></span></code></pre></div><p><strong>关键洞察</strong>:<strong>事故的根因永远是系统问题,不是人的问题</strong>——因为人会犯错是一个客观存在的、不可消除的事实。<strong>一个会因为&quot;某个工程师手抖&quot;而塌的系统,是这个系统设计错了,不是这个工程师错了</strong>。</p><hr><h2 id="二、blameless-的真意-不是不追责-是换一种追法" tabindex="-1">二、Blameless 的真意:不是不追责,是换一种追法 <a class="header-anchor" href="#二、blameless-的真意-不是不追责-是换一种追法" aria-label="Permalink to &quot;二、Blameless 的真意:不是不追责,是换一种追法&quot;">​</a></h2><h3 id="_2-1-别误解-blameless" tabindex="-1">2.1 别误解 Blameless <a class="header-anchor" href="#_2-1-别误解-blameless" aria-label="Permalink to &quot;2.1 别误解 Blameless&quot;">​</a></h3><p>很多人第一次听 Blameless 会以为是&quot;出事不追责&quot;——这是最大的误解。<strong>Blameless 不弱化责任,它把责任的对象从&quot;人的行为&quot;换成&quot;系统的漏洞&quot;</strong>:</p><table tabindex="0"><thead><tr><th>维度</th><th>Blameful 复盘</th><th>Blameless 复盘</th></tr></thead><tbody><tr><td>主语</td><td>谁犯的错</td><td>哪道防线漏了</td></tr><tr><td>问题</td><td>为什么他这么做</td><td>为什么系统允许他这么做</td></tr><tr><td>结论</td><td>处罚他 / 训练他</td><td>改流程 / 加防线 / 改工具</td></tr><tr><td>行动</td><td>警告 / 扣绩效</td><td>工程 ticket</td></tr><tr><td>效果</td><td>这个人下次小心,但系统还在</td><td>这类事故无论谁来值都不会再有</td></tr><tr><td>文化代价</td><td>隐瞒、互相甩锅</td><td>心理安全、敢报告问题</td></tr></tbody></table><p><strong>注意右下角那一格&quot;文化代价&quot;</strong>——这是 Blameless 最被低估的价值。<strong>有指责文化下,工程师学会的不是&quot;小心&quot;,是&quot;低调&quot;</strong>:</p><ul><li>小问题能压就压</li><li>出事先想怎么甩锅</li><li>别人的服务出事自己别评论</li><li>关键决策走口头不留邮件</li></ul><p><strong>这种团队的事故响应速度永远是慢的</strong>——因为问题一直在地下烂,<strong>等到它浮出水面就已经是 P0</strong>。</p><h3 id="_2-2-一个真实例子-工程师-drop-table-生产库" tabindex="-1">2.2 一个真实例子:工程师 drop table 生产库 <a class="header-anchor" href="#_2-2-一个真实例子-工程师-drop-table-生产库" aria-label="Permalink to &quot;2.2 一个真实例子:工程师 drop table 生产库&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2 月凌晨 1 点,工程师小张在排查问题时,误把生产库当成测试库,</span></span>
<span class="line"><span>执行了 DROP TABLE orders;</span></span>
<span class="line"><span>24 万条订单数据消失。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>╔══════════════════════════════════════════════════╗</span></span>
<span class="line"><span>║ Blameful 的复盘 (错误示范)                       ║</span></span>
<span class="line"><span>╠══════════════════════════════════════════════════╣</span></span>
<span class="line"><span>║ 问题: 为什么小张乱删生产数据?                    ║</span></span>
<span class="line"><span>║ 结论: 小张操作失误,警告 + 扣绩效                ║</span></span>
<span class="line"><span>║ 改进: 大家以后操作生产库要&quot;加强意识&quot;             ║</span></span>
<span class="line"><span>║                                                  ║</span></span>
<span class="line"><span>║ 一个月后:小张离职,新人小王接班                  ║</span></span>
<span class="line"><span>║ 三个月后:小王在排查问题时连错环境,又 drop 一次  ║</span></span>
<span class="line"><span>╚══════════════════════════════════════════════════╝</span></span>
<span class="line"><span></span></span>
<span class="line"><span>╔══════════════════════════════════════════════════╗</span></span>
<span class="line"><span>║ Blameless 的复盘 (正确示范)                      ║</span></span>
<span class="line"><span>╠══════════════════════════════════════════════════╣</span></span>
<span class="line"><span>║ 问题 1: 为什么生产库的 DROP 权限给了一个普通研发? ║</span></span>
<span class="line"><span>║ 问题 2: 为什么生产和测试的连接配置长得这么像?     ║</span></span>
<span class="line"><span>║ 问题 3: 为什么 DROP 操作不需要二次确认?           ║</span></span>
<span class="line"><span>║ 问题 4: 为什么没有&quot;五分钟回收站&quot;?(soft delete)  ║</span></span>
<span class="line"><span>║ 问题 5: 为什么生产终端的提示符不显眼?             ║</span></span>
<span class="line"><span>║                                                  ║</span></span>
<span class="line"><span>║ 5 个工程 ticket,2 个月内全部修完                ║</span></span>
<span class="line"><span>║ 6 个月后:相似手抖事件 0 次                      ║</span></span>
<span class="line"><span>╚══════════════════════════════════════════════════╝</span></span></code></pre></div><p><strong>两次复盘指向同一个事故,但下一次同类事故的概率完全不同</strong>。</p><h3 id="_2-3-blameless-的硬纪律" tabindex="-1">2.3 Blameless 的硬纪律 <a class="header-anchor" href="#_2-3-blameless-的硬纪律" aria-label="Permalink to &quot;2.3 Blameless 的硬纪律&quot;">​</a></h3><p>Blameless 不是软文化,它有几条<strong>比 Blameful 更硬的纪律</strong>:</p><ol><li><strong>必须找根因</strong>——不允许停在&quot;加强意识&quot;这种结论</li><li><strong>必须出 Action Items</strong>——每条有 owner / 有 due / 可验证</li><li><strong>必须 follow up</strong>——下次复盘要回顾上次 Action 的完成情况</li><li><strong>重复事故 = 复盘失败</strong>——同类事故重复发生,不是责怪当事人,是责怪上次复盘的人</li></ol><p><strong>最后一条最关键</strong>:Blameless 不是&quot;对人的失误网开一面&quot;,<strong>是把追责的对象从&quot;操作者&quot;换成&quot;上次复盘的责任人&quot;</strong>。如果你上次复盘草草收场,下次同类事故时<strong>你才是要被问的人</strong>。</p><hr><h2 id="三、5-whys-实战-挖到哪一层才算到底" tabindex="-1">三、5 Whys 实战:挖到哪一层才算到底 <a class="header-anchor" href="#三、5-whys-实战-挖到哪一层才算到底" aria-label="Permalink to &quot;三、5 Whys 实战:挖到哪一层才算到底&quot;">​</a></h2><h3 id="_3-1-5-whys-的基本方法" tabindex="-1">3.1 5 Whys 的基本方法 <a class="header-anchor" href="#_3-1-5-whys-的基本方法" aria-label="Permalink to &quot;3.1 5 Whys 的基本方法&quot;">​</a></h3><p>5 Whys 不是&quot;问 5 个为什么&quot;,是<strong>通过连续追问把表层症状一路挖到根本原因</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>表层症状 ── 为什么? ──→ 直接原因</span></span>
<span class="line"><span>              │</span></span>
<span class="line"><span>              ↓ 为什么?</span></span>
<span class="line"><span>          二层原因</span></span>
<span class="line"><span>              │</span></span>
<span class="line"><span>              ↓ 为什么?</span></span>
<span class="line"><span>          三层原因</span></span>
<span class="line"><span>              │</span></span>
<span class="line"><span>              ↓ 为什么? ......</span></span>
<span class="line"><span>              ↓</span></span>
<span class="line"><span>          根因(系统 / 流程 / 文化)</span></span></code></pre></div><p>数字&quot;5&quot;是经验值,<strong>不是教条</strong>——可能 3 层就够,可能挖到第 7 层。<strong>判断&quot;挖够了&quot;的标准</strong>:再问一次&quot;为什么&quot;,答案落到&quot;系统设计 / 流程缺陷 / 文化问题&quot;这一层,<strong>而不是&quot;某个人决定 X&quot;</strong>。</p><h3 id="_3-2-5-whys-怎么挖才不跑偏" tabindex="-1">3.2 5 Whys 怎么挖才不跑偏 <a class="header-anchor" href="#_3-2-5-whys-怎么挖才不跑偏" aria-label="Permalink to &quot;3.2 5 Whys 怎么挖才不跑偏&quot;">​</a></h3><p><strong>反例</strong>(挖偏了的方向):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>事故:订单接口错误率飙升</span></span>
<span class="line"><span>W1: 为什么? → 数据库 CPU 跑满</span></span>
<span class="line"><span>W2: 为什么? → 一个慢查询全表扫</span></span>
<span class="line"><span>W3: 为什么? → 缺索引</span></span>
<span class="line"><span>W4: 为什么? → 上线时索引没加</span></span>
<span class="line"><span>W5: 为什么? → 工程师没注意</span></span>
<span class="line"><span>结论:训练工程师 / 加强 review</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    ↑</span></span>
<span class="line"><span>    挖到 W4 已经到了&quot;系统漏洞&quot; (上线流程没拦索引)</span></span>
<span class="line"><span>    W5 又退回到&quot;人的问题&quot;,前功尽弃</span></span></code></pre></div><p><strong>正例</strong>(挖对的方向):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>事故:订单接口错误率飙升</span></span>
<span class="line"><span>W1: 为什么 → 数据库 CPU 跑满</span></span>
<span class="line"><span>W2: 为什么 → 一个慢查询全表扫</span></span>
<span class="line"><span>W3: 为什么 → 缺索引</span></span>
<span class="line"><span>W4: 为什么 → 上线时索引没加</span></span>
<span class="line"><span>W5: 为什么 → CI 没有&quot;DDL 必须有索引验证&quot;的检查</span></span>
<span class="line"><span>W6: 为什么 → 团队没有&quot;线上 SQL 必须经过 explain 验证&quot;的流程</span></span>
<span class="line"><span></span></span>
<span class="line"><span>根因:CI / CD 缺少 SQL 性能门禁</span></span>
<span class="line"><span>行动:</span></span>
<span class="line"><span>   1. 在 CI 加入 sql-lint 检查 (owner: 平台组, due: 2 周)</span></span>
<span class="line"><span>   2. 加 explain 自动跑 + p99 &gt;100ms 阻断 (owner: DBA, due: 4 周)</span></span>
<span class="line"><span>   3. 上线前必须附 explain 结果到 PR description (owner: 平台组, due: 1 周)</span></span></code></pre></div><p><strong>判断挖对没挖对的 3 条小测试</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>测试 1: 替换主语测试</span></span>
<span class="line"><span>   &quot;把当事人换成另一个工程师,这事还会发生吗?&quot;</span></span>
<span class="line"><span>   如果答案是&quot;会&quot;——挖对了(系统问题)</span></span>
<span class="line"><span>   如果答案是&quot;不会&quot;——挖偏了,要继续往下</span></span>
<span class="line"><span></span></span>
<span class="line"><span>测试 2: 时间测试</span></span>
<span class="line"><span>   &quot;如果这个问题一年前问,答案一样吗?&quot;</span></span>
<span class="line"><span>   &quot;为什么这一年里这个漏洞一直存在,直到今天才暴露?&quot;</span></span>
<span class="line"><span>   如果答案揭示了一个长期存在的盲点,挖对了</span></span>
<span class="line"><span></span></span>
<span class="line"><span>测试 3: 工程 ticket 测试</span></span>
<span class="line"><span>   &quot;这个根因能不能写成一个具体的工程任务?&quot;</span></span>
<span class="line"><span>   &quot;改 X 工具,加 Y 流程,做 Z 校验&quot;——可以 → 挖对</span></span>
<span class="line"><span>   &quot;下次大家小心 / 加强意识&quot;——不行 → 还要挖</span></span></code></pre></div><h3 id="_3-3-不要变成-为什么这个工程师手抖" tabindex="-1">3.3 不要变成&quot;为什么这个工程师手抖&quot; <a class="header-anchor" href="#_3-3-不要变成-为什么这个工程师手抖" aria-label="Permalink to &quot;3.3 不要变成&quot;为什么这个工程师手抖&quot;&quot;">​</a></h3><p>5 Whys 最容易跑偏的地方:<strong>第一层就指向人</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>错误的起手:</span></span>
<span class="line"><span>W1: 为什么数据库被 drop? → 因为小张手抖</span></span>
<span class="line"><span>W2: 为什么小张会手抖? → 因为他没看清楚环境</span></span>
<span class="line"><span>W3: 为什么他没看清楚? → 因为他疲劳</span></span>
<span class="line"><span>W4: 为什么他疲劳? → 因为他加班</span></span>
<span class="line"><span>W5: 为什么他加班? → 因为项目排期紧</span></span>
<span class="line"><span>结论:不要让工程师加班</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   ↑</span></span>
<span class="line"><span>   一路都在挖&quot;人为什么犯错&quot;,不是挖&quot;系统为什么允许犯错&quot;</span></span></code></pre></div><p><strong>正确的起手</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>W1: 为什么数据库被 drop?</span></span>
<span class="line"><span>    把这个 Why 拆成两支:</span></span>
<span class="line"><span>    A: 为什么小张能执行 DROP TABLE? (权限问题)</span></span>
<span class="line"><span>    B: 为什么 DROP TABLE 没有保护机制? (流程 / 工具问题)</span></span>
<span class="line"><span>    C: 为什么 DROP 之后没法快速恢复? (备份 / 回滚问题)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>每一支独立挖,得到 3 个根因,3 个工程 Action</span></span></code></pre></div><p><strong>5 Whys 不是单线挖,是多线挖</strong> —— 一个事故经常有多个独立漏洞,<strong>每一个漏洞都该被挖到底,每一个漏洞都该有自己的修复行动</strong>。</p><hr><h2 id="四、复盘报告模板-一份能直接抄的格式" tabindex="-1">四、复盘报告模板:一份能直接抄的格式 <a class="header-anchor" href="#四、复盘报告模板-一份能直接抄的格式" aria-label="Permalink to &quot;四、复盘报告模板:一份能直接抄的格式&quot;">​</a></h2><h3 id="_4-1-标准模板" tabindex="-1">4.1 标准模板 <a class="header-anchor" href="#_4-1-标准模板" aria-label="Permalink to &quot;4.1 标准模板&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=============================================</span></span>
<span class="line"><span>事故复盘报告</span></span>
<span class="line"><span>=============================================</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 标题</span></span>
<span class="line"><span>[一句话描述 + 严重度]</span></span>
<span class="line"><span>例: 订单接口错误率飙升 (P0)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Summary (摘要)</span></span>
<span class="line"><span>- 起止时间: YYYY-MM-DD HH:MM ~ HH:MM (持续 29 min)</span></span>
<span class="line"><span>- 严重度:   P0</span></span>
<span class="line"><span>- 影响:    估算 12,400 笔订单失败,5,200 用户感知</span></span>
<span class="line"><span>- 根因:    数据库迁移误删关键索引</span></span>
<span class="line"><span>- 修复:    回滚发布到 v2.4.6</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Timeline (时间线)</span></span>
<span class="line"><span>[摘自事故时间线,只记事实]</span></span>
<span class="line"><span>03:01 - 错误率告警触发</span></span>
<span class="line"><span>03:02 - 小王成为 IC</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Impact (影响)</span></span>
<span class="line"><span>- 业务影响: 失败订单 12,400 笔,GMV 损失 ~80 万</span></span>
<span class="line"><span>- SLO 影响: 错误预算消耗 85% (本月)</span></span>
<span class="line"><span>- 客户影响: 大客户 A / B 各有 1 次客诉</span></span>
<span class="line"><span>- 公关影响: 无 (Status Page 5 分钟内更新,无媒体)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># What Went Well (做对了什么)</span></span>
<span class="line"><span>- IC 制度运转,29 分钟内恢复</span></span>
<span class="line"><span>- Status Page 同步及时,客服话术统一</span></span>
<span class="line"><span>- 战时频道纪律好,无刷屏</span></span>
<span class="line"><span></span></span>
<span class="line"><span># What Went Wrong (哪里出问题)</span></span>
<span class="line"><span>- migration 删除关键索引前未做性能评估</span></span>
<span class="line"><span>- CI 缺少 DDL 安全检查</span></span>
<span class="line"><span>- DBA 未参与该次发布的 review</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Root Cause Analysis (5 Whys 分析)</span></span>
<span class="line"><span>[多线挖,见上一节]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>主线 A: 为什么删了索引能上线</span></span>
<span class="line"><span>   W1 → W2 → W3 → W4 → W5</span></span>
<span class="line"><span>   根因: CI 缺 SQL 安全检查</span></span>
<span class="line"><span></span></span>
<span class="line"><span>主线 B: 为什么没人 review</span></span>
<span class="line"><span>   W1 → W2 → W3</span></span>
<span class="line"><span>   根因: 流程里 SQL 变更没有 DBA 强制 review</span></span>
<span class="line"><span></span></span>
<span class="line"><span>主线 C: 为什么影响这么大才发现</span></span>
<span class="line"><span>   W1 → W2 → W3 → W4</span></span>
<span class="line"><span>   根因: 慢查询告警阈值过高</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Action Items</span></span>
<span class="line"><span>[见 5.x 节,每条有 owner / due / verifiable]</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Lessons Learned (经验教训)</span></span>
<span class="line"><span>- 数据库变更和代码变更必须分开发布</span></span>
<span class="line"><span>- 索引删除 = 高风险,必须 DBA 单独 review</span></span>
<span class="line"><span>- 复盘的下次跟踪在 1 个月后</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Appendix (附录)</span></span>
<span class="line"><span>- 完整时间线</span></span>
<span class="line"><span>- 监控截图</span></span>
<span class="line"><span>- 相关 PR / Commit 链接</span></span>
<span class="line"><span>- 战时频道归档</span></span></code></pre></div><h3 id="_4-2-报告写作的-5-条硬要求" tabindex="-1">4.2 报告写作的 5 条硬要求 <a class="header-anchor" href="#_4-2-报告写作的-5-条硬要求" aria-label="Permalink to &quot;4.2 报告写作的 5 条硬要求&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 文中不出现&quot;由于 XX 同学的疏忽&quot;这类表述</span></span>
<span class="line"><span>   → 改成&quot;由于流程 / 工具 / 系统的某项缺失&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 文中不出现&quot;加强 / 强化 / 严格 / 提高意识&quot;这类口号</span></span>
<span class="line"><span>   → 改成具体的工程任务</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 所有结论必须有数据 / 监控截图佐证</span></span>
<span class="line"><span>   → 不允许&quot;感觉是 / 大概是 / 估计是&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 每个 Action Item 必须 SMART (Specific / Measurable /</span></span>
<span class="line"><span>   Achievable / Relevant / Time-bound)</span></span>
<span class="line"><span>   → &quot;加强测试&quot;不是 Action,&quot;为 order-api 加合约测试,</span></span>
<span class="line"><span>     在 CI 中阻断&quot; 才是</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 报告必须公开 (公司内全公开)</span></span>
<span class="line"><span>   → 不能藏在某个团队 wiki,要让其他团队也能学</span></span></code></pre></div><h3 id="_4-3-谁来写复盘报告" tabindex="-1">4.3 谁来写复盘报告 <a class="header-anchor" href="#_4-3-谁来写复盘报告" aria-label="Permalink to &quot;4.3 谁来写复盘报告&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>事故 owner (出事服务的负责人) → 起草</span></span>
<span class="line"><span>SRE / IC                       → 审阅</span></span>
<span class="line"><span>所有相关人                       → 补充</span></span>
<span class="line"><span>SRE Lead / CTO                 → 终审 + 公布</span></span>
<span class="line"><span></span></span>
<span class="line"><span>时间窗口: 事故后 5 个工作日内必须完成</span></span>
<span class="line"><span>   超时不交 = 这个 owner 的下一次值班顺延</span></span>
<span class="line"><span>   (不是惩罚,是把&quot;复盘&quot;刻进默认流程)</span></span></code></pre></div><hr><h2 id="五、action-items-复盘最容易死掉的地方" tabindex="-1">五、Action Items:复盘最容易死掉的地方 <a class="header-anchor" href="#五、action-items-复盘最容易死掉的地方" aria-label="Permalink to &quot;五、Action Items:复盘最容易死掉的地方&quot;">​</a></h2><h3 id="_5-1-action-items-的硬要求" tabindex="-1">5.1 Action Items 的硬要求 <a class="header-anchor" href="#_5-1-action-items-的硬要求" aria-label="Permalink to &quot;5.1 Action Items 的硬要求&quot;">​</a></h3><p>每一条 Action Item 必须满足 5 条:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Owner — 具体到一个人(不是&quot;平台组&quot;)</span></span>
<span class="line"><span>2. Due Date — 具体到一天(不是&quot;尽快&quot;)</span></span>
<span class="line"><span>3. Verifiable — 完成时怎么验证(不是&quot;加强 X&quot;)</span></span>
<span class="line"><span>4. Severity — 这条不做下次事故会有多严重</span></span>
<span class="line"><span>5. Tracking — 在哪个系统里跟(JIRA / GitHub Issue / Linear)</span></span></code></pre></div><p><strong>一个反例</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>错的 Action Items:</span></span>
<span class="line"><span>- 加强 SQL 评审 (owner: 平台组, due: 后续)</span></span>
<span class="line"><span>- 改进监控 (owner: SRE, due: 长期)</span></span>
<span class="line"><span>- 团队培训 (owner: 组长, due: 持续)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   ↑ 三条都没法跟踪,半年后这三条还在那儿挂着</span></span></code></pre></div><p><strong>对应的正例</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>对的 Action Items:</span></span>
<span class="line"><span>- 在 CI 加 sqlcheck 静态扫描,所有 DDL PR 必须通过</span></span>
<span class="line"><span>  Owner: 张三 / 平台组</span></span>
<span class="line"><span>  Due: 2026-05-25 (2 周)</span></span>
<span class="line"><span>  Verify: PR #1234 合并 + 监控显示 sqlcheck 已生效</span></span>
<span class="line"><span>  Severity: 高(同类事故下次概率 → 0)</span></span>
<span class="line"><span>  Tracking: PLATFORM-456</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- 慢查询告警阈值从 5s 改为 500ms,加入主告警群</span></span>
<span class="line"><span>  Owner: 李四 / DBA</span></span>
<span class="line"><span>  Due: 2026-05-18 (1 周)</span></span>
<span class="line"><span>  Verify: Alertmanager 配置 PR 合并,本周新增告警数据</span></span>
<span class="line"><span>  Severity: 中(发现速度提升)</span></span>
<span class="line"><span>  Tracking: SRE-789</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- 编写&quot;高危 DDL 操作 Runbook&quot;,列出索引 / 表结构变更检查表</span></span>
<span class="line"><span>  Owner: 王五 / DBA</span></span>
<span class="line"><span>  Due: 2026-05-25</span></span>
<span class="line"><span>  Verify: Runbook 在 wiki 发布 + 团队 review</span></span>
<span class="line"><span>  Severity: 中(标准化降低人因风险)</span></span>
<span class="line"><span>  Tracking: DOC-101</span></span></code></pre></div><h3 id="_5-2-action-item-反模式" tabindex="-1">5.2 Action Item 反模式 <a class="header-anchor" href="#_5-2-action-item-反模式" aria-label="Permalink to &quot;5.2 Action Item 反模式&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>反模式 1: &quot;加强 XX&quot;</span></span>
<span class="line"><span>   症状: 一片&quot;加强测试 / 加强 review / 加强意识&quot;</span></span>
<span class="line"><span>   后果: 没法跟踪,半年后还挂着</span></span>
<span class="line"><span>   修复: 必须翻译成具体工程任务</span></span>
<span class="line"><span></span></span>
<span class="line"><span>反模式 2: Owner 是组而不是人</span></span>
<span class="line"><span>   症状: &quot;Owner: 平台组&quot; &quot;Owner: 后端团队&quot;</span></span>
<span class="line"><span>   后果: 责任弥散,没人真负责</span></span>
<span class="line"><span>   修复: 必须指定一个人,组长也行,但必须有名字</span></span>
<span class="line"><span></span></span>
<span class="line"><span>反模式 3: Due Date 是 &quot;持续 / 长期 / Q3&quot;</span></span>
<span class="line"><span>   症状: 没有具体日期</span></span>
<span class="line"><span>   后果: 永远 due 不到</span></span>
<span class="line"><span>   修复: 必须落到具体某一天</span></span>
<span class="line"><span></span></span>
<span class="line"><span>反模式 4: 一次列 20 条</span></span>
<span class="line"><span>   症状: 复盘热情高,Action 列了 20 条</span></span>
<span class="line"><span>   后果: 半年完成 3 条</span></span>
<span class="line"><span>   修复: 最多 7 条,按 Severity 排序,P0 一定要 4 周内完成</span></span>
<span class="line"><span></span></span>
<span class="line"><span>反模式 5: 列完不跟踪</span></span>
<span class="line"><span>   症状: 复盘结束 = 任务结束</span></span>
<span class="line"><span>   后果: Action 永远在文档里,不在系统里</span></span>
<span class="line"><span>   修复: 所有 Action 当天进 JIRA / GitHub Issue,</span></span>
<span class="line"><span>        每周一次扫描完成率</span></span></code></pre></div><h3 id="_5-3-postmortem-of-the-postmortem" tabindex="-1">5.3 Postmortem of the Postmortem <a class="header-anchor" href="#_5-3-postmortem-of-the-postmortem" aria-label="Permalink to &quot;5.3 Postmortem of the Postmortem&quot;">​</a></h3><p><strong>最关键的一条规则</strong>:Action Items 完成率必须自己监控,<strong>作为一个核心指标贴在团队墙上</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>团队复盘健康度看板(每月更新):</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  本月新增 Action Items:       12</span></span>
<span class="line"><span>  本月完成 Action Items:        7</span></span>
<span class="line"><span>  本月超期未完成:               3</span></span>
<span class="line"><span>  本月完成率:                  58%       ← 健康线 80% 以上</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  累计 Action Items 池:         48</span></span>
<span class="line"><span>  累计完成:                    35</span></span>
<span class="line"><span>  累计完成率:                  73%</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  最老的未完成 Action:</span></span>
<span class="line"><span>    PLATFORM-321: 编写 K8s Runbook (Due: 2025-12-15, 超期 5 个月)</span></span>
<span class="line"><span>                  Owner: 张三</span></span>
<span class="line"><span>                  ↑ 这条要拎出来在团队会上单独讨论</span></span></code></pre></div><p><strong>为什么这一条至关重要</strong>:<strong>&quot;做了复盘&quot;不等于&quot;修了系统&quot;——只有 Action 完成才等于修了</strong>。一个团队的真实可靠性,<strong>不看复盘开了多少次,看 Action 完成率有多少</strong>。</p><h3 id="_5-4-复盘后跟踪的-cadence" tabindex="-1">5.4 复盘后跟踪的 cadence <a class="header-anchor" href="#_5-4-复盘后跟踪的-cadence" aria-label="Permalink to &quot;5.4 复盘后跟踪的 cadence&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>事故 D 日:        事故发生</span></span>
<span class="line"><span>D + 2~5 天:      复盘会议,产出 Action Items</span></span>
<span class="line"><span>D + 7 天:        所有 Action 进入 ticket 系统,owner 确认</span></span>
<span class="line"><span>D + 14 天:       第一次进度检查(SRE Lead 主持)</span></span>
<span class="line"><span>D + 30 天:       中期检查,看高 Severity Action 是否完成</span></span>
<span class="line"><span>D + 60 天:       全部 Action 完成或重新评估</span></span>
<span class="line"><span>D + 90 天:       同类事故指标观察 — 同类事故有没有再来</span></span>
<span class="line"><span></span></span>
<span class="line"><span>每月:           复盘健康度报表上传</span></span>
<span class="line"><span>每季度:         所有未完成 Action 重新审议</span></span></code></pre></div><hr><h2 id="六、复盘会议-谁主持、谁参加、什么时候开" tabindex="-1">六、复盘会议:谁主持、谁参加、什么时候开 <a class="header-anchor" href="#六、复盘会议-谁主持、谁参加、什么时候开" aria-label="Permalink to &quot;六、复盘会议:谁主持、谁参加、什么时候开&quot;">​</a></h2><h3 id="_6-1-时间窗口-不要太早也不要太晚" tabindex="-1">6.1 时间窗口:不要太早也不要太晚 <a class="header-anchor" href="#_6-1-时间窗口-不要太早也不要太晚" aria-label="Permalink to &quot;6.1 时间窗口:不要太早也不要太晚&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>事故关闭 → 复盘</span></span>
<span class="line"><span>   太早 (&lt; 2 天):  当事人还在情绪里,讲不清楚</span></span>
<span class="line"><span>                  时间线和监控数据还没整理好</span></span>
<span class="line"><span>   合适 (2-5 天):  事故的记忆还鲜活,情绪也冷静了</span></span>
<span class="line"><span>                  数据 / 监控 / 截图都拉出来了</span></span>
<span class="line"><span>   太晚 (&gt; 1 周): 记忆开始失真,细节丢失</span></span>
<span class="line"><span>                  心理上&quot;已经过去了&quot;</span></span></code></pre></div><p><strong>雷打不动:5 个工作日内开完</strong>。超期不开 = SRE Lead 的责任。</p><h3 id="_6-2-谁主持-中立-有威信" tabindex="-1">6.2 谁主持:中立 + 有威信 <a class="header-anchor" href="#_6-2-谁主持-中立-有威信" aria-label="Permalink to &quot;6.2 谁主持:中立 + 有威信&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>最佳人选:</span></span>
<span class="line"><span>   - SRE Lead / 平台 Lead (中立)</span></span>
<span class="line"><span>   - 没出事的服务 Lead (中立)</span></span>
<span class="line"><span>   - 经验丰富的资深工程师</span></span>
<span class="line"><span></span></span>
<span class="line"><span>绝对不能:</span></span>
<span class="line"><span>   - 出事服务的 Lead (利益相关)</span></span>
<span class="line"><span>   - 出事的当事人 (心理负担)</span></span>
<span class="line"><span>   - 直接 manager (变批斗会)</span></span>
<span class="line"><span>   - 完全外行 (问不出关键 Why)</span></span></code></pre></div><p><strong>主持人的核心职责不是&quot;问&quot;,是&quot;挡&quot;</strong>——挡掉所有&quot;小张为什么这么蠢&quot;式的发问,把会议拉回&quot;系统漏洞&quot;维度。</p><h3 id="_6-3-谁参加-相关人-一个不相关的人" tabindex="-1">6.3 谁参加:相关人 + 一个不相关的人 <a class="header-anchor" href="#_6-3-谁参加-相关人-一个不相关的人" aria-label="Permalink to &quot;6.3 谁参加:相关人 + 一个不相关的人&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>必须到:</span></span>
<span class="line"><span>   - 事故 IC</span></span>
<span class="line"><span>   - Ops 当事人(动手的那些)</span></span>
<span class="line"><span>   - Scribe(记时间线的)</span></span>
<span class="line"><span>   - 服务 owner</span></span>
<span class="line"><span>   - 上下游服务相关人</span></span>
<span class="line"><span>   - SRE / DBA / 平台代表(看根因领域)</span></span>
<span class="line"><span>   - Comms 代表(看对外影响)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>强烈建议:</span></span>
<span class="line"><span>   - 一个完全不相关的人(其他业务线的工程师)</span></span>
<span class="line"><span>     原因: 他不在情绪里,会问出&quot;为什么 X 这么诡异?&quot;</span></span>
<span class="line"><span>           这种内部人觉得理所当然的好问题</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不建议:</span></span>
<span class="line"><span>   - 高管 (CTO / VP) — 让人不敢说真话,事后通报即可</span></span>
<span class="line"><span>   - 完全外行 — 浪费时间</span></span>
<span class="line"><span>   - 复盘人数 &gt; 10 人 — 会变成走过场,不要超过 8 人</span></span></code></pre></div><h3 id="_6-4-会议流程-一份能跑的-60-分钟-agenda" tabindex="-1">6.4 会议流程:一份能跑的 60 分钟 agenda <a class="header-anchor" href="#_6-4-会议流程-一份能跑的-60-分钟-agenda" aria-label="Permalink to &quot;6.4 会议流程:一份能跑的 60 分钟 agenda&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=================================================</span></span>
<span class="line"><span>复盘会议 Agenda (60 分钟)</span></span>
<span class="line"><span>=================================================</span></span>
<span class="line"><span></span></span>
<span class="line"><span>00:00 - 05:00  开场 + 重申 Blameless 原则</span></span>
<span class="line"><span>   主持人开场白:</span></span>
<span class="line"><span>   &quot;今天我们是来找系统漏洞的,不是来找责任人的。</span></span>
<span class="line"><span>    任何&#39;某人的错&#39;式的发言,我会打断。&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>05:00 - 15:00  Timeline 回顾 (Scribe 主讲)</span></span>
<span class="line"><span>   过一遍时间线</span></span>
<span class="line"><span>   有任何遗漏 / 不清楚的地方,在此补充</span></span>
<span class="line"><span></span></span>
<span class="line"><span>15:00 - 25:00  影响评估</span></span>
<span class="line"><span>   业务影响、SLO 影响、客户影响、公关影响</span></span>
<span class="line"><span>   数字必须有依据</span></span>
<span class="line"><span></span></span>
<span class="line"><span>25:00 - 45:00  Root Cause 挖掘 (5 Whys)</span></span>
<span class="line"><span>   主持人引导,所有人参与</span></span>
<span class="line"><span>   多线并行,挖到工程 ticket 层</span></span>
<span class="line"><span></span></span>
<span class="line"><span>45:00 - 55:00  Action Items 设计</span></span>
<span class="line"><span>   每条 SMART</span></span>
<span class="line"><span>   Owner 当场认领</span></span>
<span class="line"><span>   Due 当场定</span></span>
<span class="line"><span></span></span>
<span class="line"><span>55:00 - 60:00  收尾</span></span>
<span class="line"><span>   总结根因</span></span>
<span class="line"><span>   总结 Action</span></span>
<span class="line"><span>   下次同类事故的 follow-up 时间</span></span>
<span class="line"><span>   感谢所有参与者(包括当事人)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>=================================================</span></span></code></pre></div><p><strong>主持人最重要的一句话,放在会议开场</strong>:</p><blockquote><p>&quot;我们今天不是来追究&#39;谁犯了错&#39;,是来找&#39;我们的系统在哪里漏了&#39;。<strong>任何在这里说真话的人,都不会因为说出真相而被追责</strong>——这是我们这个团队能学到东西的唯一前提。&quot;</p></blockquote><p>这句话不是套话,是<strong>契约</strong>——主持人说出来之后,后续如果出现&quot;批斗&quot;语气,他必须立刻打断。如果他自己破坏这条契约,<strong>下次没人会在复盘上说真话</strong>。</p><hr><h2 id="七、severity-rating-分级复盘-小事故走简化流程" tabindex="-1">七、Severity Rating:分级复盘,小事故走简化流程 <a class="header-anchor" href="#七、severity-rating-分级复盘-小事故走简化流程" aria-label="Permalink to &quot;七、Severity Rating:分级复盘,小事故走简化流程&quot;">​</a></h2><p>不是每个事故都需要 60 分钟会议 + 5 页报告。<strong>滥用复盘会让团队疲劳,真出 P0 时反而草草收场</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Severity   触发条件                  复盘形式</span></span>
<span class="line"><span>─────────  ──────────────────────  ─────────────────</span></span>
<span class="line"><span>P0         全站宕 / 数据丢          强制 blameless 完整流程</span></span>
<span class="line"><span>           核心交易停 ≥ 15 分钟      60 分钟会议 + 完整报告</span></span>
<span class="line"><span>                                    所有相关人 + 高管通报</span></span>
<span class="line"><span></span></span>
<span class="line"><span>P1         影响 &gt; 1% 用户            建议完整复盘</span></span>
<span class="line"><span>           核心功能不可用 ≥ 30 分钟  30 分钟会议 + 简化报告</span></span>
<span class="line"><span>                                    相关人 + SRE Lead</span></span>
<span class="line"><span></span></span>
<span class="line"><span>P2         影响 &lt; 1% 用户            轻量复盘</span></span>
<span class="line"><span>           降级可用 / 边缘功能       书面报告(不开会)</span></span>
<span class="line"><span>                                    Owner + SRE review</span></span>
<span class="line"><span></span></span>
<span class="line"><span>P3         自愈成功的告警            只做记录</span></span>
<span class="line"><span>           单实例异常                合并到月度复盘合集</span></span></code></pre></div><p><strong>重点</strong>:<strong>P3 不开复盘会,但 P3 要月度合集</strong>——一个月一次,把所有 P3 拉出来扫一遍,<strong>找统计规律</strong>(某个服务 P3 频发 = 这个服务有隐性问题)。</p><hr><h2 id="八、复盘文化建设-从-0-到-1-怎么落地" tabindex="-1">八、复盘文化建设:从 0 到 1 怎么落地 <a class="header-anchor" href="#八、复盘文化建设-从-0-到-1-怎么落地" aria-label="Permalink to &quot;八、复盘文化建设:从 0 到 1 怎么落地&quot;">​</a></h2><h3 id="_8-1-不要照抄-google-netflix" tabindex="-1">8.1 不要照抄 Google / Netflix <a class="header-anchor" href="#_8-1-不要照抄-google-netflix" aria-label="Permalink to &quot;8.1 不要照抄 Google / Netflix&quot;">​</a></h3><p>Google 的 Postmortem 文化是真的——他们有专门的&quot;Postmortem Wiki&quot;,所有事故公开,新人入职就刷以前的 Postmortem 学习。Netflix 的&quot;Chaos 文化&quot;更夸张——主动制造故障,故障比例当 KPI 看。</p><p><strong>但小团队照抄会立刻死</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Google 抄过来的失败:</span></span>
<span class="line"><span>   - 要求所有 P2 以上事故都写 5 页报告 → 工程师 burnout</span></span>
<span class="line"><span>   - 要求所有报告全公司公开 → 大家学会写水帐</span></span>
<span class="line"><span>   - 要求每周一次 Postmortem Review Meeting → 30 个人各自做自己的事</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   后果: 半年后所有人都开始隐瞒 P2 事故,只汇报&quot;修完了&quot;</span></span></code></pre></div><p><strong>中型团队的落地路径</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>0 → 1:</span></span>
<span class="line"><span>   开始要求所有 P0 写报告,模板尽量简单(2 页够了)</span></span>
<span class="line"><span>   不要求公开,只在团队内部存档</span></span>
<span class="line"><span>   每月统计 Action 完成率,作为团队 OKR 的一部分</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1 → 2:</span></span>
<span class="line"><span>   要求 P1 也走简化复盘</span></span>
<span class="line"><span>   报告全公司开放,但不强制其他团队学</span></span>
<span class="line"><span>   开始做&quot;经典事故合集&quot;,方便新人学</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2 → 3:</span></span>
<span class="line"><span>   全公司公开所有 Postmortem</span></span>
<span class="line"><span>   开始引入&quot;无关人提问&quot;角色</span></span>
<span class="line"><span>   开始有专门的&quot;复盘协调员&quot;角色</span></span></code></pre></div><p>每一步只在<strong>上一步真正稳定后</strong>才走 — 步子太大,文化崩。</p><h3 id="_8-2-文化建设的-4-个反模式" tabindex="-1">8.2 文化建设的 4 个反模式 <a class="header-anchor" href="#_8-2-文化建设的-4-个反模式" aria-label="Permalink to &quot;8.2 文化建设的 4 个反模式&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>反模式 1: CEO / CTO 说&quot;我们要 Blameless&quot;但自己开会就批人</span></span>
<span class="line"><span>   后果: 没人信,团队学会&quot;嘴上 Blameless,行动甩锅&quot;</span></span>
<span class="line"><span>   修复: 高管不参加复盘会(看报告就够了)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>反模式 2: 复盘走过场,Action 不跟踪</span></span>
<span class="line"><span>   后果: 半年下来,所有人觉得复盘是浪费时间</span></span>
<span class="line"><span>   修复: 把 Action 完成率作为团队的硬指标</span></span>
<span class="line"><span></span></span>
<span class="line"><span>反模式 3: 只有 P0 才复盘</span></span>
<span class="line"><span>   后果: P1 / P2 经验白白浪费</span></span>
<span class="line"><span>   修复: 分级复盘,P2 可以轻量但必须存档</span></span>
<span class="line"><span></span></span>
<span class="line"><span>反模式 4: 复盘报告写完锁起来</span></span>
<span class="line"><span>   后果: 知识在 owner 脑子里,新人继续踩同一个坑</span></span>
<span class="line"><span>   修复: 报告全公司可读,新人入职必读最近 10 个 P0</span></span></code></pre></div><h3 id="_8-3-一个见效快的工程师本能训练" tabindex="-1">8.3 一个见效快的工程师本能训练 <a class="header-anchor" href="#_8-3-一个见效快的工程师本能训练" aria-label="Permalink to &quot;8.3 一个见效快的工程师本能训练&quot;">​</a></h3><p>每次有同事讲事故,<strong>注意自己第一反应</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>不健康的本能:</span></span>
<span class="line"><span>   &quot;他怎么这么菜啊&quot;</span></span>
<span class="line"><span>   &quot;我才不会犯这种错&quot;</span></span>
<span class="line"><span>   &quot;幸好不是我值班&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>健康的本能:</span></span>
<span class="line"><span>   &quot;这事如果是我,我会不会也犯?&quot;</span></span>
<span class="line"><span>   &quot;我们系统是不是也有这个漏洞?&quot;</span></span>
<span class="line"><span>   &quot;下次类似情况,我有什么提前防的机制?&quot;</span></span></code></pre></div><p><strong>Blameless 不只是会议上的规则,是每一个工程师的本能</strong>。这个本能不靠喊口号,靠每次反思:<strong>&quot;如果是我,我也会犯这个错吗?&quot;</strong> — 如果会,系统就有问题。</p><hr><h2 id="九、反例-批斗大会的话术-以及怎么救回来" tabindex="-1">九、反例:批斗大会的话术,以及怎么救回来 <a class="header-anchor" href="#九、反例-批斗大会的话术-以及怎么救回来" aria-label="Permalink to &quot;九、反例:批斗大会的话术,以及怎么救回来&quot;">​</a></h2><p>下面是真实复盘里常听到的话术,主持人必须能识别并拦回去。</p><h3 id="反例-1-这个人不该手抖" tabindex="-1">反例 1:&quot;这个人不该手抖&quot; <a class="header-anchor" href="#反例-1-这个人不该手抖" aria-label="Permalink to &quot;反例 1:&quot;这个人不该手抖&quot;&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>错的发言:</span></span>
<span class="line"><span>   &quot;小张那天就不应该手抖删生产库,做技术的基本素质都没有。&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>主持人应该说:</span></span>
<span class="line"><span>   &quot;等一下,&#39;手抖&#39;不是我们能修的东西。</span></span>
<span class="line"><span>    我们今天要找的是:为什么系统允许一个手抖能 drop 生产表?</span></span>
<span class="line"><span>    咱们换个角度,为什么 DROP 操作没有二次确认?&quot;</span></span></code></pre></div><h3 id="反例-2-我之前就说这是定时炸弹" tabindex="-1">反例 2:&quot;我之前就说这是定时炸弹&quot; <a class="header-anchor" href="#反例-2-我之前就说这是定时炸弹" aria-label="Permalink to &quot;反例 2:&quot;我之前就说这是定时炸弹&quot;&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>错的发言:</span></span>
<span class="line"><span>   &quot;这个服务的代码我之前 review 就觉得有问题,我说过这是定时炸弹。&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>主持人应该说:</span></span>
<span class="line"><span>   &quot;你当时怎么记录的?有 PR comment 吗?有 issue 吗?</span></span>
<span class="line"><span>    如果没有,我们今天要补一个 Action:</span></span>
<span class="line"><span>    重要风险点必须落到 issue,不能停在&#39;我说过&#39;。&quot;</span></span></code></pre></div><h3 id="反例-3-我们就不该信任他" tabindex="-1">反例 3:&quot;我们就不该信任他&quot; <a class="header-anchor" href="#反例-3-我们就不该信任他" aria-label="Permalink to &quot;反例 3:&quot;我们就不该信任他&quot;&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>错的发言:</span></span>
<span class="line"><span>   &quot;新人不应该有生产权限,我们就不该信任他。&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>主持人应该说:</span></span>
<span class="line"><span>   &quot;权限模型不应该建立在&#39;信任谁&#39;之上。</span></span>
<span class="line"><span>    我们今天要看:权限矩阵是什么时候定的?</span></span>
<span class="line"><span>    新人应该默认多少权限?生产权限是怎么提权的?</span></span>
<span class="line"><span>    把信任问题翻译成权限设计问题。&quot;</span></span></code></pre></div><h3 id="反例-4-以后大家都注意点" tabindex="-1">反例 4:&quot;以后大家都注意点&quot; <a class="header-anchor" href="#反例-4-以后大家都注意点" aria-label="Permalink to &quot;反例 4:&quot;以后大家都注意点&quot;&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>错的发言:</span></span>
<span class="line"><span>   &quot;总之以后大家做生产操作都注意点。&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>主持人应该说:</span></span>
<span class="line"><span>   &quot;&#39;注意&#39;不是一个 Action,&#39;注意&#39;不能 code review,</span></span>
<span class="line"><span>    &#39;注意&#39;不能 CI 检查,&#39;注意&#39;不能告警。</span></span>
<span class="line"><span>    我们要把这句话翻译成 3 条具体的工程动作。&quot;</span></span></code></pre></div><h3 id="反例-5-沉默" tabindex="-1">反例 5:沉默 <a class="header-anchor" href="#反例-5-沉默" aria-label="Permalink to &quot;反例 5:沉默&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>症状:</span></span>
<span class="line"><span>   主持人问&quot;为什么 X?&quot;,所有人低头不说话。</span></span>
<span class="line"><span>   尤其是当事人在场时。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>主持人应该:</span></span>
<span class="line"><span>   不要点名当事人。</span></span>
<span class="line"><span>   先点一个**不相关的人**:&quot;小李你的系统也有类似机制,</span></span>
<span class="line"><span>   你觉得这种情况会怎么发生?&quot;</span></span>
<span class="line"><span>   破冰后再回到当事人。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   或者: 让当事人最后发言 — 别人都说完,</span></span>
<span class="line"><span>        他听到所有人都把矛头指向系统而不是他,</span></span>
<span class="line"><span>        他才敢说真话。</span></span></code></pre></div><hr><h2 id="十、何时不该上完整复盘" tabindex="-1">十、何时不该上完整复盘 <a class="header-anchor" href="#十、何时不该上完整复盘" aria-label="Permalink to &quot;十、何时不该上完整复盘&quot;">​</a></h2><p>跟事故响应一样,<strong>复盘也不该滥用</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>不需要完整复盘的情况:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 自愈成功的告警 (P3)</span></span>
<span class="line"><span>   → 月度合集即可</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 短时间内重复出现的同根因事故</span></span>
<span class="line"><span>   → 不重新挖根因,直接 follow up 上次的 Action 为什么没做</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 演练 / 混沌产生的事故</span></span>
<span class="line"><span>   → 复盘演练本身(响应速度 / 流程是否顺畅)</span></span>
<span class="line"><span>     不复盘&quot;系统漏洞&quot;(那是设计目的)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 第三方完全不可控的故障(云厂商区域宕)</span></span>
<span class="line"><span>   → 复盘&quot;我们的依赖韧性&quot;,不是云厂商的事故本身</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 已知问题的再次触发(明知有 bug 没修)</span></span>
<span class="line"><span>   → 不开会,直接执行原计划修</span></span>
<span class="line"><span>     如果是因为&quot;没排上期&quot;导致没修,复盘排期机制</span></span></code></pre></div><hr><h2 id="十一、踩坑提醒" tabindex="-1">十一、踩坑提醒 <a class="header-anchor" href="#十一、踩坑提醒" aria-label="Permalink to &quot;十一、踩坑提醒&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Blameless 等于不追责</span></span>
<span class="line"><span>   → 错。Blameless 把追责从&quot;人&quot;转到&quot;系统&quot;,纪律更硬</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 复盘开成感想会</span></span>
<span class="line"><span>   → 没有 Action,等于没开</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. Action Items 不跟踪</span></span>
<span class="line"><span>   → 写出来不修等于没写。完成率是核心指标</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 复盘报告锁起来</span></span>
<span class="line"><span>   → 知识没复用,新人继续踩坑</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 只有 P0 才复盘</span></span>
<span class="line"><span>   → P1 / P2 的经验是最值钱的(频次高、代价小)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. 复盘会让高管参加</span></span>
<span class="line"><span>   → 大家不敢说真话,看报告就够了</span></span>
<span class="line"><span></span></span>
<span class="line"><span>7. 一个事故只挖一条主线</span></span>
<span class="line"><span>   → 多数事故有多个独立漏洞,要多线挖</span></span>
<span class="line"><span></span></span>
<span class="line"><span>8. Action Items 列 20 条</span></span>
<span class="line"><span>   → 完成不了的 Action 是负债,7 条以内,排优先级</span></span>
<span class="line"><span></span></span>
<span class="line"><span>9. 复盘 owner 自己写报告又自己审</span></span>
<span class="line"><span>   → 必须中立的人审,否则会自动美化</span></span>
<span class="line"><span></span></span>
<span class="line"><span>10. 同类事故再来时只追当事人</span></span>
<span class="line"><span>    → 真正要追的是&quot;上次复盘为什么没拦住&quot;——上次的 Action owner</span></span></code></pre></div><hr><h2 id="十二、写在最后" tabindex="-1">十二、写在最后 <a class="header-anchor" href="#十二、写在最后" aria-label="Permalink to &quot;十二、写在最后&quot;">​</a></h2><p>复盘这件事,<strong>最难的不是开会,是文化</strong>。一个团队能不能开出 Blameless 复盘,跟工具无关,跟流程关系也不大——<strong>取决于团队里的资深人和管理者,能不能在压力下守住&quot;对事不对人&quot;</strong>。</p><p>这件事的难度被严重低估:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>理论上:    &quot;我们要 Blameless&quot;</span></span>
<span class="line"><span>实操中:    凌晨四点的 P0 修完了,大家眼睛通红,客户在催,</span></span>
<span class="line"><span>           CEO 在群里 @ 你,某个工程师明显手抖了。</span></span>
<span class="line"><span>           这一刻,你是要做 Blameless 的解释,</span></span>
<span class="line"><span>           还是要&quot;今天就先这样,先把人骂了出出气&quot;?</span></span></code></pre></div><p>99% 的团队选了后者,然后他们的事故响应能力就停在那一刻不再进步了。</p><p><strong>所以这一篇的核心,不是教你写复盘模板,是请你做一个承诺:从下一个事故开始,你的复盘会议上不允许出现&quot;是 XX 的错&quot;。</strong> 哪怕当事人真的犯了低级错误,你也要把这句话翻译成&quot;我们的系统应该有 X 来防止这种错&quot;。</p><p>工程师对系统的信任,不是靠&quot;我相信我的同事都很厉害&quot;建立的——是靠&quot;<strong>就算我犯了错,系统也能兜住,公司也不会让我背锅</strong>&quot;建立的。这种信任建立起来,团队才能在压力下还说真话;<strong>说真话的团队,才能学到东西;能学到东西的团队,事故才会越来越少</strong>。</p><p><strong>这是 Blameless 真正的意义——不是道德,是工程</strong>。</p><blockquote><p>下一篇 <code>34-FinOps与平台工程.md</code> 是这个系列的最后一篇。讲完事故响应和复盘,我们要回到这个系列开篇问过的一个问题:<strong>&quot;可靠性到底要花多少钱?&quot;</strong>——以及 SRE 这个工种在 2026 年正在往哪里进化。<strong>这个系列开篇是 MTTR / MTBF / Change Failure Rate 三个数字,收尾要加一个数字:$/QPS,以及一个角色:Platform Engineer</strong>。</p></blockquote>`,142)])])}const g=n(e,[["render",t]]);export{h as __pageData,g as default};
